    /**
     * AC 4.1 (AI-generated, corrected):
     * Given a valid move, when tryMove is called, it returns true, the source is
     * empty, the jumped peg is removed, and the destination has a peg.
     *
     * Original AI error: used wrong coordinates (tried to jump over an empty hole).
     * Correction: adjusted to (3,1) -> (3,3), which jumps over the peg at (3,2).
     */
    @Test
    void ac4_1_tryMove_validJump_removesJumpedPeg() {
        // English 7x7: centre (3,3) is empty.
        // (3,1) has a peg, (3,2) has a peg -> jump (3,1) over (3,2) into (3,3)
        Board board = new Board(7, BoardType.ENGLISH);

        boolean result = board.tryMove(3, 1, 3, 3);

        assertTrue(result,          "Valid move should return true");
        assertEquals(HoleState.EMPTY, board.getHole(3, 1), "Source must be empty after move");
        assertEquals(HoleState.EMPTY, board.getHole(3, 2), "Jumped peg must be removed");
        assertEquals(HoleState.PEG,   board.getHole(3, 3), "Destination must have peg");
    }

