    // Test helpers
    // ════════════════════════════════════════════════════════════════════════════

    /** Executes the first legal move it can find on the board. */
    private boolean makeFirstAvailableMove(Board board) {
        int[][] dirs = { {0, 2}, {0, -2}, {2, 0}, {-2, 0} };
        for (int r = 0; r < board.getSize(); r++)
            for (int c = 0; c < board.getSize(); c++)
                if (board.getHole(r, c) == HoleState.PEG)
                    for (int[] d : dirs)
                        if (board.tryMove(r, c, r + d[0], c + d[1]))
                            return true;
        return false;
    }

    /**
     * Plays moves until the board reaches approximately {@code targetPegs} pegs.
     * Stops early if no moves remain.
     */
    private void driveToNPegs(Board board, int targetPegs) {
        int safety = 0;
        while (board.getPegCount() > targetPegs && board.hasValidMoves() && safety++ < 1000) {
            makeFirstAvailableMove(board);
        }
    }
